                        Isso indica que o comando 'npm run build' falhou ou não foi executado.
                    </div>
                </div>
            </body>
        </html>
    `);
});

// 7. PORTA E BINDING (Sincronizado com Port Mapping 3000 do Coolify)
const PORT = process.env.PORT || 3000;
app.listen(PORT, '0.0.0.0', () => {
    console.log(`[IdentificaPix] Rodando em http://0.0.0.0:${PORT}`);
});

